#!/bin/bash
# =============================================================================
# deploy_ninja_patch_watcher.sh
# Version: 4.5
#
# Deploys ninja_patch_watcher v4.5 — daemon + agent architecture.
#
# Installs:
#   - /usr/local/bin/ninja_patch_watcher.sh        (root LaunchDaemon)
#   - /usr/local/bin/ninja_patch_watcher_agent.sh  (user LaunchAgent)
#   - /Library/LaunchDaemons/ninja.patch.watcher.plist
#   - /Library/LaunchAgents/ninja.patch.watcher.agent.plist
#
# Deploy via NinjaOne as a Shell Script:
#   - Run as: root
#   - Run as logged-in user: No
#   - Frequency: Once
# =============================================================================

set -e

DAEMON_SCRIPT="/usr/local/bin/ninja_patch_watcher.sh"
AGENT_SCRIPT="/usr/local/bin/ninja_patch_watcher_agent.sh"
DAEMON_PLIST="/Library/LaunchDaemons/ninja.patch.watcher.plist"
AGENT_PLIST="/Library/LaunchAgents/ninja.patch.watcher.agent.plist"
NEWSYSLOG_CONF="/etc/newsyslog.d/ninja_patch_watcher.conf"
DAEMON_LABEL="ninja.patch.watcher"
AGENT_LABEL="ninja.patch.watcher.agent"
VERSION="4.7"

log() {
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] $*"
}

log "Starting ninja_patch_watcher v${VERSION} deployment"

if [[ ! -x "/usr/local/bin/dialog" ]]; then
    log "ERROR: swiftDialog not found at /usr/local/bin/dialog"
    exit 1
fi
log "swiftDialog found: $(/usr/local/bin/dialog --version 2>/dev/null | head -1)"

if [[ ! -d "/Applications/NinjaRMMAgent" ]]; then
    log "ERROR: NinjaRMMAgent not found"
    exit 1
fi
log "NinjaRMM agent found"

CONSOLE_USER=$(stat -f "%Su" /dev/console 2>/dev/null)
if [[ -z "$CONSOLE_USER" || "$CONSOLE_USER" == "root" ]]; then
    log "WARNING: No logged-in user detected"
    CONSOLE_USER="root"
fi
log "Console user: $CONSOLE_USER"

log "Writing daemon script to $DAEMON_SCRIPT"
echo "" | base64 -d > "$DAEMON_SCRIPT"
chmod +x "$DAEMON_SCRIPT"
log "Daemon script written"

log "Writing agent script to $AGENT_SCRIPT"
echo "" | base64 -d > "$AGENT_SCRIPT"
chmod +x "$AGENT_SCRIPT"
log "Agent script written"

log "Writing LaunchDaemon plist to $DAEMON_PLIST"
cat > "$DAEMON_PLIST" << 'DAEMONPLISTEOF'
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
    <key>Label</key>
    <string>ninja.patch.watcher</string>
    <key>ProgramArguments</key>
    <array>
        <string>/bin/bash</string>
        <string>/usr/local/bin/ninja_patch_watcher.sh</string>
    </array>
    <key>RunAtLoad</key>
    <true/>
    <key>KeepAlive</key>
    <true/>
    <key>ThrottleInterval</key>
    <integer>30</integer>
    <key>StandardOutPath</key>
    <string>/var/log/ninja_patch_watcher_launchd.log</string>
    <key>StandardErrorPath</key>
    <string>/var/log/ninja_patch_watcher_launchd.log</string>
    <key>Nice</key>
    <integer>5</integer>
</dict>
</plist>
DAEMONPLISTEOF

chown root:wheel "$DAEMON_PLIST"
chmod 644 "$DAEMON_PLIST"
log "LaunchDaemon plist written"

log "Writing LaunchAgent plist to $AGENT_PLIST"
cat > "$AGENT_PLIST" << 'AGENTPLISTEOF'
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
    <key>Label</key>
    <string>ninja.patch.watcher.agent</string>
    <key>ProgramArguments</key>
    <array>
        <string>/bin/bash</string>
        <string>/usr/local/bin/ninja_patch_watcher_agent.sh</string>
    </array>
    <key>RunAtLoad</key>
    <true/>
    <key>KeepAlive</key>
    <true/>
    <key>ThrottleInterval</key>
    <integer>10</integer>
    <key>StandardOutPath</key>
    <string>/tmp/ninja_patch_watcher_agent.log</string>
    <key>StandardErrorPath</key>
    <string>/tmp/ninja_patch_watcher_agent.log</string>
</dict>
</plist>
AGENTPLISTEOF

chown root:wheel "$AGENT_PLIST"
chmod 644 "$AGENT_PLIST"
log "LaunchAgent plist written"

log "Configuring log rotation"
cat > "$NEWSYSLOG_CONF" << 'NEWSYSLOGEOF'
/var/log/ninja_patch_watcher.log          root:wheel  644  5  1024  *  J
/var/log/ninja_patch_watcher_launchd.log  root:wheel  644  5  1024  *  J
/tmp/ninja_patch_watcher_agent.log        root:wheel  644  5  1024  *  J
NEWSYSLOGEOF

log "Loading LaunchDaemon"
if launchctl list | grep -q "${DAEMON_LABEL}" 2>/dev/null; then
    log "Existing daemon found — unloading first"
    launchctl bootout system/"$DAEMON_LABEL" 2>/dev/null || true
    sleep 2
fi
launchctl bootstrap system "$DAEMON_PLIST"
sleep 2
if launchctl list | grep -q "$DAEMON_LABEL"; then
    log "LaunchDaemon loaded successfully"
else
    log "ERROR: LaunchDaemon failed to load"
    exit 1
fi

log "Loading LaunchAgent for $CONSOLE_USER"
if [[ "$CONSOLE_USER" != "root" ]]; then
    CONSOLE_UID=$(id -u "$CONSOLE_USER" 2>/dev/null)
    if launchctl asuser "$CONSOLE_UID" launchctl list | grep -q "$AGENT_LABEL" 2>/dev/null; then
        log "Existing agent found — unloading first"
        launchctl asuser "$CONSOLE_UID" launchctl bootout "gui/${CONSOLE_UID}/${AGENT_LABEL}" 2>/dev/null || true
        sleep 1
    fi
    launchctl asuser "$CONSOLE_UID" launchctl bootstrap "gui/${CONSOLE_UID}" "$AGENT_PLIST"
    sleep 2
    if launchctl asuser "$CONSOLE_UID" launchctl list | grep -q "$AGENT_LABEL" 2>/dev/null; then
        log "LaunchAgent loaded successfully for $CONSOLE_USER"
    else
        log "WARNING: LaunchAgent may not have loaded — it will load at next login"
    fi
else
    log "No logged-in user — LaunchAgent will load at next login automatically"
fi

log "Deployment complete — v${VERSION} active"
log "Daemon log:  tail -f /var/log/ninja_patch_watcher.log"
log "Agent log:   tail -f /tmp/ninja_patch_watcher_agent.log"
exit 0